sql:
SELECT COUNT(user_id) 
FROM users 
WHERE role = 'Customer';

SELECT p.product_id, p.product_name, p.description, p.category_id, p.product_type, p.manufacturing_date, p.warranty_period
FROM products p
JOIN ratings r ON p.product_id = r.product_id
WHERE r.rating = (
    SELECT MAX(rating) FROM ratings
);

external_knowledge:
- "highly-rated items" refers to products with a rating over 4;
- "over a dozen inquiries" means more than 10 questions;
- "addressed" questions are considered "answered".

sql:
SELECT product_id, product_name 
FROM products 
WHERE product_id NOT IN (SELECT product_id FROM user_questions);

external_knowledge:
- 'highest-rated popularity' refers to product types with average ratings above the overall average;
- 'leading categories' imply the most frequent category for each product type with a high rating;
- 'from the most impressive to the least' means sorted by average ratings in descending order.

sql:
SELECT user_name, email, job_title 
FROM users 
WHERE department IN ('Sales', 'Marketing');
